settings.custom_liquid:
{% assign imagen_galeria = images['webpay.jpg'] %}
{% if imagen_galeria %}
  <style>
    .imagen-full-mobile {
      max-width: 100%;
      height: auto;
    }
    @media only screen and (max-width: 767px) {
      .imagen-full-mobile {
        width: 100%;
        display: block;
      }
    }
  </style>
  {{ imagen_galeria | image_url: width: 1200 | image_tag: 
    loading: 'lazy', 
    class: 'mi-clase-personalizada imagen-full-mobile', 
    alt: 'Métodos de pago seguros' 
  }}
{% endif %}
